import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import './App.css';

const API_BASE = 'http://localhost:3001/api';

// Helper to get full image URL
const getImageUrl = (path) => {
  if (!path) return null;
  if (path.startsWith('http')) return path;
  return `http://localhost:3001/uploads/${path}`;
};

// API helper
const api = {
  get: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!res.ok) {
      throw new Error(`HTTP error! status: ${res.status}`);
    }
    return res.json();
  },
  post: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(data)
    });
    if (!res.ok) {
      throw new Error(`HTTP error! status: ${res.status}`);
    }
    return res.json();
  },
  postForm: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${token}` },
      body: data
    });
    if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
    return res.json();
  },
  put: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'PUT',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(data)
    });
    if (!res.ok) {
      throw new Error(`HTTP error! status: ${res.status}`);
    }
    return res.json();
  },
  putForm: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'PUT',
      headers: { 'Authorization': `Bearer ${token}` },
      body: data
    });
    if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
    return res.json();
  },
  delete: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    if (!res.ok) {
      throw new Error(`HTTP error! status: ${res.status}`);
    }
    return res.json();
  }
};

// Login Page
function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_BASE}/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });
      const data = await res.json();
      if (data.success) {
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        navigate('/dashboard');
      } else {
        setError(data.error || 'Login failed');
      }
    } catch (err) {
      setError('Connection failed');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <div className="login-logo">
            <svg viewBox="0 0 100 100" className="logo-svg">
              <circle cx="50" cy="50" r="45" fill="none" stroke="url(#grad1)" strokeWidth="8"/>
              <path d="M30 50 L45 65 L70 35" stroke="#10b981" strokeWidth="8" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
              <defs>
                <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
                  <stop offset="0%" style={{stopColor: '#6366f1', stopOpacity: 1}} />
                  <stop offset="100%" style={{stopColor: '#8b5cf6', stopOpacity: 1}} />
                </linearGradient>
              </defs>
            </svg>
          </div>
          <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          <p className="login-subtitle">Member Management System</p>
        </div>
        <form onSubmit={handleLogin}>
          <div className="form-group">
            <label>Username</label>
            <input type="text" value={username} onChange={e => setUsername(e.target.value)} placeholder="Enter username" required />
          </div>
          <div className="form-group">
            <label>Password</label>
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter password" required />
          </div>
          {error && <div className="error-message">{error}</div>}
          <button type="submit" className="btn-login">Sign In</button>
        </form>
        <div className="login-footer">
          <p>Demo credentials: admin / admin123</p>
        </div>
      </div>
    </div>
  );
}

// Dashboard
function Dashboard() {
  const [stats, setStats] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetchStats();
    const storedUser = localStorage.getItem('user');
    if (storedUser) setUser(JSON.parse(storedUser));
  }, []);

  const fetchStats = async () => {
    try {
      const data = await api.get('/stats');
      if (data.success) setStats(data.stats);
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    window.location.href = '/';
  };

  return (
    <div className="dashboard">
      <header className="dashboard-header">
        <div className="header-content">
          <div className="header-left">
            <div className="header-logo">
              <svg viewBox="0 0 100 100" className="logo-svg-small">
                <circle cx="50" cy="50" r="45" fill="none" stroke="url(#grad1)" strokeWidth="6"/>
                <path d="M30 50 L45 65 L70 35" stroke="#10b981" strokeWidth="6" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                <defs>
                  <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" style={{stopColor: '#6366f1', stopOpacity: 1}} />
                    <stop offset="100%" style={{stopColor: '#8b5cf6', stopOpacity: 1}} />
                  </linearGradient>
                </defs>
              </svg>
            </div>
            <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          </div>
          <div className="header-right">
            {user && <span className="user-name">{user.full_name || user.username}</span>}
            <button className="btn-logout" onClick={handleLogout}>Logout</button>
          </div>
        </div>
      </header>

      <nav className="main-nav">
        <div className="nav-content">
          <Link to="/dashboard" className="nav-link active">Dashboard</Link>
          <Link to="/members" className="nav-link">Members</Link>
          <Link to="/loans" className="nav-link">Loans</Link>
          <Link to="/shares" className="nav-link">Shares</Link>
          <Link to="/savings" className="nav-link">Savings</Link>
          <Link to="/monthly-savings" className="nav-link">Monthly Savings</Link>
          <Link to="/citizenship" className="nav-link">Citizenship</Link>
          <Link to="/profile" className="nav-link">Profile</Link>
        </div>
      </nav>

      <main className="dashboard-content">
        <div className="welcome-section">
          <h2>Welcome to Sanaduk Saving and Credit Cooperative Ltd.</h2>
          <p>A premier financial cooperative dedicated to serving our community members with comprehensive savings, loan, and share management services.</p>
        </div>

        {stats && (
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-icon members-icon">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
                  <circle cx="9" cy="7" r="4"/>
                  <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
                  <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
                </svg>
              </div>
              <div className="stat-info">
                <span className="stat-value">{stats.members}</span>
                <span className="stat-label">Total Members</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon loans-icon">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/>
                </svg>
              </div>
              <div className="stat-info">
                <span className="stat-value">{stats.activeLoans}</span>
                <span className="stat-label">Active Loans</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon savings-icon">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <rect x="2" y="7" width="20" height="14" rx="2" ry="2"/>
                  <path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"/>
                </svg>
              </div>
              <div className="stat-info">
                <span className="stat-value">{stats.activeSavings}</span>
                <span className="stat-label">Active Savings</span>
              </div>
            </div>

            <div className="stat-card">
              <div className="stat-icon shares-icon">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="12" cy="12" r="10"/>
                  <path d="M16 8h-6a2 2 0 1 0 0 4h4a2 2 0 1 1 0 4H8"/>
                  <path d="M12 18V6"/>
                </svg>
              </div>
              <div className="stat-info">
                <span className="stat-value">{stats.activeShares}</span>
                <span className="stat-label">Active Shares</span>
              </div>
            </div>
          </div>
        )}

        <div className="info-cards">
          <div className="info-card">
            <h3>Quick Actions</h3>
            <div className="quick-actions">
              <Link to="/members" className="action-btn">Add New Member</Link>
              <Link to="/loans" className="action-btn">Create Loan</Link>
              <Link to="/savings" className="action-btn">New Savings Account</Link>
            </div>
          </div>

          <div className="info-card">
            <h3>About Us</h3>
            <p>Sanaduk Saving and Credit Cooperative Ltd. is committed to providing financial services to our community members with transparency, fairness, and excellent customer service.</p>
          </div>
        </div>
      </main>
    </div>
  );
}

// Members Page
function MembersPage() {
  const [members, setMembers] = useState([]);
  const [form, setForm] = useState({
    member_number: '', member_name: '', address: '', phone: '',
    email: '', membership_type: 'Saving', joined_date: '', status: 'Active'
  });
  const [editingId, setEditingId] = useState(null);
  const [viewingMember, setViewingMember] = useState(null);
  const [savingsAccounts, setSavingsAccounts] = useState({});
  const [loanAccounts, setLoanAccounts] = useState({});
  const [shareAccounts, setShareAccounts] = useState({});

  useEffect(() => { fetchMembers(); }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
      if (membersData.length > 0) {
        fetchAccountsForMembers(membersData);
      }
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const fetchAccountsForMembers = async (membersList) => {
    for (const member of membersList) {
      try {
        const savingsRes = await api.get(`/savings/member/${member.id}`);
        const loanRes = await api.get(`/loans/member/${member.id}`);
        const shareRes = await api.get(`/shares/member/${member.id}`);
        
        setSavingsAccounts(prev => ({ ...prev, [member.id]: (savingsRes.data || savingsRes || []).filter(s => s.status === 'active') }));
        setLoanAccounts(prev => ({ ...prev, [member.id]: (loanRes.data || loanRes || []).filter(l => l.status === 'active') }));
        setShareAccounts(prev => ({ ...prev, [member.id]: (shareRes.data || shareRes || []).filter(s => s.status === 'active') }));
      } catch (error) {
        console.error('Error fetching accounts:', error);
      }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/members/${editingId}`, form);
        alert('Member updated successfully!');
      } else {
        await api.post('/members', form);
        alert('Member added successfully!');
      }
      setForm({ member_number: '', member_name: '', address: '', phone: '', email: '', membership_type: 'Saving', joined_date: '', status: 'Active' });
      setEditingId(null);
      fetchMembers();
    } catch (error) {
      console.error('Error saving member:', error);
      alert('Error: ' + error.message);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this member?')) {
      try {
        await api.delete(`/members/${id}`);
        fetchMembers();
      } catch (error) {
        console.error('Error deleting member:', error);
      }
    }
  };

  const handleEdit = (member) => {
    setForm(member);
    setEditingId(member.id);
  };

  const handleView = async (member) => {
    setViewingMember(member);
    try {
      const savingsRes = await api.get(`/savings/member/${member.id}`);
      const loanRes = await api.get(`/loans/member/${member.id}`);
      const shareRes = await api.get(`/shares/member/${member.id}`);
      
      setSavingsAccounts(prev => ({ ...prev, [member.id]: (savingsRes.data || savingsRes || []) }));
      setLoanAccounts(prev => ({ ...prev, [member.id]: (loanRes.data || loanRes || []) }));
      setShareAccounts(prev => ({ ...prev, [member.id]: (shareRes.data || shareRes || []) }));
    } catch (error) {
      console.error('Error fetching accounts:', error);
    }
  };

  const generateMemberNumber = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
    setForm(prev => ({ ...prev, member_number: `MEM/${year}/${random}` }));
  };

  return (
    <div className="members-page">
      <div className="page-header">
        <h1>Members</h1>
        <p>Manage cooperative members and their accounts</p>
      </div>

      <div className="form-section">
        <h3>{editingId ? 'Edit Member' : 'Add New Member'}</h3>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <div className="form-group">
              <label>Member Number</label>
              <div className="input-with-btn">
                <input type="text" value={form.member_number} onChange={e => setForm({...form, member_number: e.target.value})} required placeholder="MEM/2024/001" />
                <button type="button" className="btn-generate" onClick={generateMemberNumber}>Generate</button>
              </div>
            </div>
            <div className="form-group">
              <label>Member Name</label>
              <input type="text" value={form.member_name} onChange={e => setForm({...form, member_name: e.target.value})} required placeholder="Full Name" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Phone</label>
              <input type="tel" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} placeholder="Phone Number" />
            </div>
            <div className="form-group">
              <label>Email</label>
              <input type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} placeholder="Email Address" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Address</label>
              <input type="text" value={form.address} onChange={e => setForm({...form, address: e.target.value})} placeholder="Address" />
            </div>
            <div className="form-group">
              <label>Membership Type</label>
              <select value={form.membership_type} onChange={e => setForm({...form, membership_type: e.target.value})}>
                <option value="Saving">Saving</option>
                <option value="Regular">Regular</option>
                <option value="Special">Special</option>
              </select>
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Joined Date</label>
              <input type="date" value={form.joined_date} onChange={e => setForm({...form, joined_date: e.target.value})} />
            </div>
            <div className="form-group">
              <label>Status</label>
              <select value={form.status} onChange={e => setForm({...form, status: e.target.value})}>
                <option value="Active">Active</option>
                <option value="Inactive">Inactive</option>
              </select>
            </div>
          </div>
          <div className="form-actions">
            <button type="submit" className="btn-primary">{editingId ? 'Update' : 'Add Member'}</button>
            {editingId && <button type="button" className="btn-secondary" onClick={() => { setEditingId(null); setForm({ member_number: '', member_name: '', address: '', phone: '', email: '', membership_type: 'Saving', joined_date: '', status: 'Active' }); }}>Cancel</button>}
          </div>
        </form>
      </div>

      <div className="table-section">
        <h3>Members List ({members.length})</h3>
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Member No.</th>
                <th>Name</th>
                <th>Phone</th>
                <th>Email</th>
                <th>Type</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {members.map(member => (
                <tr key={member.id}>
                  <td>{member.member_number}</td>
                  <td>{member.member_name}</td>
                  <td>{member.phone}</td>
                  <td>{member.email}</td>
                  <td><span className={`badge ${member.membership_type.toLowerCase()}`}>{member.membership_type}</span></td>
                  <td><span className={`status-badge ${member.status.toLowerCase()}`}>{member.status}</span></td>
                  <td>
                    <button className="btn-sm" onClick={() => handleView(m)}>View</button>
                    <button className="btn-sm" onClick={() => handleEdit(m)}>Edit</button>
                    <button className="btn-sm btn-danger" onClick={() => handleDelete(m.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingMember && (
        <div className="modal-overlay" onClick={() => setViewingMember(null)}>
          <div className="modal-content view-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Member Details</h2>
              <button className="btn-close" onClick={() => setViewingMember(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="detail-section">
                <h3>Personal Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Member Number:</strong> {viewingMember.member_number}</div>
                  <div className="detail-item"><strong>Name:</strong> {viewingMember.member_name}</div>
                  <div className="detail-item"><strong>Phone:</strong> {viewingMember.phone}</div>
                  <div className="detail-item"><strong>Email:</strong> {viewingMember.email}</div>
                  <div className="detail-item"><strong>Address:</strong> {viewingMember.address}</div>
                  <div className="detail-item"><strong>Membership Type:</strong> {viewingMember.membership_type}</div>
                  <div className="detail-item"><strong>Joined Date:</strong> {viewingMember.joined_date}</div>
                  <div className="detail-item"><strong>Status:</strong> <span className={`status-badge ${viewingMember.status.toLowerCase()}`}>{viewingMember.status}</span></div>
                </div>
              </div>

              <div className="detail-section">
                <h3>Savings Accounts</h3>
                {savingsAccounts[viewingMember.id]?.length > 0 ? (
                  <div className="account-cards">
                    {savingsAccounts[viewingMember.id].map(s => (
                      <div key={s.id} className="account-card">
                        <div className="account-title">Account: {s.account_number}</div>
                        <div className="account-details">
                          <span>Balance: Rs. {s.current_balance?.toLocaleString()}</span>
                          <span>Type: {s.account_type}</span>
                          <span>Rate: {s.interest_rate}%</span>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : <p className="no-data">No savings accounts</p>}
              </div>

              <div className="detail-section">
                <h3>Loan Accounts</h3>
                {loanAccounts[viewingMember.id]?.length > 0 ? (
                  <div className="account-cards">
                    {loanAccounts[viewingMember.id].map(l => (
                      <div key={l.id} className="account-card loan-card">
                        <div className="account-title">Loan: {l.loan_number}</div>
                        <div className="account-details">
                          <span>Amount: Rs. {l.principal_amount?.toLocaleString()}</span>
                          <span>Rate: {l.interest_rate}%</span>
                          <span>Balance: Rs. {l.remaining_balance?.toLocaleString()}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : <p className="no-data">No loan accounts</p>}
              </div>

              <div className="detail-section">
                <h3>Share Accounts</h3>
                {shareAccounts[viewingMember.id]?.length > 0 ? (
                  <div className="account-cards">
                    {shareAccounts[viewingMember.id].map(s => (
                      <div key={s.id} className="account-card share-card">
                        <div className="account-title">Shares: {s.share_number}</div>
                        <div className="account-details">
                          <span>Shares: {s.number_of_shares}</span>
                          <span>Amount: Rs. {s.total_amount?.toLocaleString()}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : <p className="no-data">No share accounts</p>}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setViewingMember(null)}>Close</button>
              <button className="btn-primary" onClick={() => { handleEdit(viewingMember); setViewingMember(null); }}>Edit</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Loans Page
function LoansPage() {
  const [loans, setLoans] = useState([]);
  const [members, setMembers] = useState([]);
  const [form, setForm] = useState({
    loan_number: '', member_id: '', loan_type: 'Personal', principal_amount: '',
    interest_rate: '12', loan_term_months: '12', loan_started_date_bs: '',
    disbursement_date: '', maturity_date: '', purpose: '', collateral_details: '',
    guarantor_name: '', guarantor_phone: '', guarantor_citizenship: '', status: 'active'
  });
  const [editingId, setEditingId] = useState(null);
  const [viewingLoan, setViewingLoan] = useState(null);

  useEffect(() => { fetchLoans(); fetchMembers(); }, []);

  const fetchLoans = async () => {
    try {
      const response = await api.get('/loans');
      const loansData = response.data || response || [];
      setLoans(Array.isArray(loansData) ? loansData : []);
    } catch (error) {
      console.error('Error fetching loans:', error);
      setLoans([]);
    }
  };

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const generateLoanNumber = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
    setForm(prev => ({ ...prev, loan_number: `LN/${year}/${random}` }));
  };

  const calculateMaturity = () => {
    if (form.disbursement_date && form.loan_term_months) {
      const start = new Date(form.disbursement_date);
      start.setMonth(start.getMonth() + parseInt(form.loan_term_months));
      setForm(prev => ({ ...prev, maturity_date: start.toISOString().split('T')[0] }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/loans/${editingId}`, form);
        alert('Loan updated successfully!');
      } else {
        await api.post('/loans', { ...form, remaining_balance: parseFloat(form.principal_amount) });
        alert('Loan created successfully!');
      }
      setForm({
        loan_number: '', member_id: '', loan_type: 'Personal', principal_amount: '',
        interest_rate: '12', loan_term_months: '12', loan_started_date_bs: '',
        disbursement_date: '', maturity_date: '', purpose: '', collateral_details: '',
        guarantor_name: '', guarantor_phone: '', guarantor_citizenship: '', status: 'active'
      });
      setEditingId(null);
      fetchLoans();
    } catch (error) {
      console.error('Error saving loan:', error);
      alert('Error: ' + error.message);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this loan?')) {
      try {
        await api.delete(`/loans/${id}`);
        fetchLoans();
      } catch (error) {
        console.error('Error deleting loan:', error);
      }
    }
  };

  const handleEdit = (loan) => {
    setForm(loan);
    setEditingId(loan.id);
  };

  const handleView = (loan) => {
    setViewingLoan(loan);
  };

  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  return (
    <div className="loans-page">
      <div className="page-header">
        <h1>Loans</h1>
        <p>Manage member loans and financing</p>
      </div>

      <div className="form-section">
        <h3>{editingId ? 'Edit Loan' : 'Create New Loan'}</h3>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <div className="form-group">
              <label>Loan Number</label>
              <div className="input-with-btn">
                <input type="text" value={form.loan_number} onChange={e => setForm({...form, loan_number: e.target.value})} required placeholder="LN/2024/0001" />
                <button type="button" className="btn-generate" onClick={generateLoanNumber}>Generate</button>
              </div>
            </div>
            <div className="form-group">
              <label>Member</label>
              <select value={form.member_id} onChange={e => setForm({...form, member_id: e.target.value})} required>
                <option value="">Select Member</option>
                {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
              </select>
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Loan Type</label>
              <select value={form.loan_type} onChange={e => setForm({...form, loan_type: e.target.value})}>
                <option value="Personal">Personal</option>
                <option value="Business">Business</option>
                <option value="Emergency">Emergency</option>
                <option value="Housing">Housing</option>
                <option value="Education">Education</option>
              </select>
            </div>
            <div className="form-group">
              <label>Principal Amount (Rs.)</label>
              <input type="number" value={form.principal_amount} onChange={e => setForm({...form, principal_amount: e.target.value})} required placeholder="100000" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Interest Rate (%)</label>
              <input type="number" step="0.01" value={form.interest_rate} onChange={e => setForm({...form, interest_rate: e.target.value})} required placeholder="12" />
            </div>
            <div className="form-group">
              <label>Loan Term (Months)</label>
              <input type="number" value={form.loan_term_months} onChange={e => setForm({...form, loan_term_months: e.target.value})} required placeholder="12" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Start Date (BS)</label>
              <input type="text" value={form.loan_started_date_bs} onChange={e => setForm({...form, loan_started_date_bs: e.target.value})} placeholder="2080/01/01" />
            </div>
            <div className="form-group">
              <label>Disbursement Date</label>
              <input type="date" value={form.disbursement_date} onChange={e => { setForm({...form, disbursement_date: e.target.value}); calculateMaturity(); }} />
            </div>
            <div className="form-group">
              <label>Maturity Date</label>
              <input type="date" value={form.maturity_date} onChange={e => setForm({...form, maturity_date: e.target.value})} />
            </div>
          </div>
          <div className="form-group">
            <label>Purpose</label>
            <textarea value={form.purpose} onChange={e => setForm({...form, purpose: e.target.value})} placeholder="Purpose of loan"></textarea>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Collateral Details</label>
              <input type="text" value={form.collateral_details} onChange={e => setForm({...form, collateral_details: e.target.value})} placeholder="Collateral information" />
            </div>
            <div className="form-group">
              <label>Guarantor Name</label>
              <input type="text" value={form.guarantor_name} onChange={e => setForm({...form, guarantor_name: e.target.value})} placeholder="Guarantor name" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Guarantor Phone</label>
              <input type="tel" value={form.guarantor_phone} onChange={e => setForm({...form, guarantor_phone: e.target.value})} placeholder="Guarantor phone" />
            </div>
            <div className="form-group">
              <label>Guarantor Citizenship No.</label>
              <input type="text" value={form.guarantor_citizenship} onChange={e => setForm({...form, guarantor_citizenship: e.target.value})} placeholder="Guarantor citizenship number" />
            </div>
          </div>
          <div className="form-actions">
            <button type="submit" className="btn-primary">{editingId ? 'Update Loan' : 'Create Loan'}</button>
            {editingId && <button type="button" className="btn-secondary" onClick={() => { setEditingId(null); setForm({ loan_number: '', member_id: '', loan_type: 'Personal', principal_amount: '', interest_rate: '12', loan_term_months: '12', loan_started_date_bs: '', disbursement_date: '', maturity_date: '', purpose: '', collateral_details: '', guarantor_name: '', guarantor_phone: '', guarantor_citizenship: '', status: 'active' }); }}>Cancel</button>}
          </div>
        </form>
      </div>

      <div className="table-section">
        <h3>Loans List ({loans.length})</h3>
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Loan No.</th>
                <th>Member</th>
                <th>Type</th>
                <th>Amount</th>
                <th>Rate</th>
                <th>Balance</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {loans.map(l => (
                <tr key={l.id}>
                  <td>{l.loan_number}</td>
                  <td>{getMemberName(l.member_id)}</td>
                  <td>{l.loan_type}</td>
                  <td>Rs. {parseFloat(l.principal_amount || 0).toLocaleString()}</td>
                  <td>{l.interest_rate}%</td>
                  <td>Rs. {parseFloat(l.remaining_balance || 0).toLocaleString()}</td>
                  <td><span className={`status-badge ${l.status}`}>{l.status}</span></td>
                  <td>
                    <button className="btn-sm" onClick={() => handleView(l)}>View</button>
                    <button className="btn-sm" onClick={() => handleEdit(l)}>Edit</button>
                    <button className="btn-sm btn-danger" onClick={() => handleDelete(l.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingLoan && (
        <div className="modal-overlay" onClick={() => setViewingLoan(null)}>
          <div className="modal-content view-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Loan Details</h2>
              <button className="btn-close" onClick={() => setViewingLoan(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="detail-section">
                <h3>Loan Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Loan Number:</strong> {viewingLoan.loan_number}</div>
                  <div className="detail-item"><strong>Type:</strong> {viewingLoan.loan_type}</div>
                  <div className="detail-item"><strong>Principal:</strong> Rs. {parseFloat(viewingLoan.principal_amount || 0).toLocaleString()}</div>
                  <div className="detail-item"><strong>Interest Rate:</strong> {viewingLoan.interest_rate}%</div>
                  <div className="detail-item"><strong>Term:</strong> {viewingLoan.loan_term_months} months</div>
                  <div className="detail-item"><strong>Remaining Balance:</strong> Rs. {parseFloat(viewingLoan.remaining_balance || 0).toLocaleString()}</div>
                  <div className="detail-item"><strong>Start Date (BS):</strong> {viewingLoan.loan_started_date_bs}</div>
                  <div className="detail-item"><strong>Disbursement:</strong> {viewingLoan.disbursement_date}</div>
                  <div className="detail-item"><strong>Maturity:</strong> {viewingLoan.maturity_date}</div>
                  <div className="detail-item"><strong>Status:</strong> <span className={`status-badge ${viewingLoan.status}`}>{viewingLoan.status}</span></div>
                </div>
              </div>
              {viewingLoan.purpose && <div className="detail-section"><h3>Purpose</h3><p>{viewingLoan.purpose}</p></div>}
              {viewingLoan.collateral_details && <div className="detail-section"><h3>Collateral</h3><p>{viewingLoan.collateral_details}</p></div>}
              {(viewingLoan.guarantor_name || viewingLoan.guarantor_phone || viewingLoan.guarantor_citizenship) && (
                <div className="detail-section">
                  <h3>Guarantor Information</h3>
                  <div className="detail-grid">
                    <div className="detail-item"><strong>Name:</strong> {viewingLoan.guarantor_name}</div>
                    <div className="detail-item"><strong>Phone:</strong> {viewingLoan.guarantor_phone}</div>
                    <div className="detail-item"><strong>Citizenship:</strong> {viewingLoan.guarantor_citizenship}</div>
                  </div>
                </div>
              )}
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setViewingLoan(null)}>Close</button>
              <button className="btn-primary" onClick={() => { handleEdit(viewingLoan); setViewingLoan(null); }}>Edit Loan</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Shares Page
function SharesPage() {
  const [shares, setShares] = useState([]);
  const [members, setMembers] = useState([]);
  const [form, setForm] = useState({
    share_number: '', member_id: '', number_of_shares: '', share_price: '100',
    total_amount: '', purchase_date_bs: '', status: 'active'
  });
  const [editingId, setEditingId] = useState(null);
  const [viewingShare, setViewingShare] = useState(null);

  useEffect(() => { fetchShares(); fetchMembers(); }, []);

  const fetchShares = async () => {
    try {
      const response = await api.get('/shares');
      const sharesData = response.data || response || [];
      setShares(Array.isArray(sharesData) ? sharesData : []);
    } catch (error) {
      console.error('Error fetching shares:', error);
      setShares([]);
    }
  };

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const generateShareNumber = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
    setForm(prev => ({ ...prev, share_number: `SH/${year}/${random}` }));
  };

  const calculateTotal = () => {
    if (form.number_of_shares && form.share_price) {
      setForm(prev => ({ ...prev, total_amount: parseInt(form.number_of_shares) * parseFloat(form.share_price) }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/shares/${editingId}`, form);
        alert('Share updated successfully!');
      } else {
        await api.post('/shares', form);
        alert('Share created successfully!');
      }
      setForm({
        share_number: '', member_id: '', number_of_shares: '', share_price: '100',
        total_amount: '', purchase_date_bs: '', status: 'active'
      });
      setEditingId(null);
      fetchShares();
    } catch (error) {
      console.error('Error saving share:', error);
      alert('Error: ' + error.message);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this share?')) {
      try {
        await api.delete(`/shares/${id}`);
        fetchShares();
      } catch (error) {
        console.error('Error deleting share:', error);
      }
    }
  };

  const handleEdit = (share) => {
    setForm(share);
    setEditingId(share.id);
  };

  const handleView = (share) => {
    setViewingShare(share);
  };

  const getMemberName = (id) => members.find(m => m.id == id)?.member_name || 'Unknown';

  return (
    <div className="shares-page">
