              </select>
            </div>
          </div>
          <div className="form-actions">
            <button type="submit" className="btn-primary">{editingId ? 'Update Share' : 'Purchase Shares'}</button>
            {editingId && <button type="button" className="btn-secondary" onClick={() => { setEditingId(null); setForm({ share_number: '', member_id: '', number_of_shares: '', share_price: '100', total_amount: '', purchase_date_bs: '', status: 'active' }); }}>Cancel</button>}
          </div>
        </form>
      </div>

      <div className="table-section">
        <h3>Shares List ({shares.length})</h3>
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Share No.</th>
                <th>Member</th>
                <th>Shares</th>
                <th>Price/Share</th>
                <th>Total</th>
                <th>Date</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {shares.map(s => (
                <tr key={s.id}>
                  <td>{s.share_number}</td>
                  <td>{getMemberName(s.member_id)}</td>
                  <td>{s.number_of_shares}</td>
                  <td>Rs. {parseFloat(s.share_price || 0).toLocaleString()}</td>
                  <td>Rs. {parseFloat(s.total_amount || 0).toLocaleString()}</td>
                  <td>{s.purchase_date_bs}</td>
                  <td><span className={`status-badge ${s.status}`}>{s.status}</span></td>
                  <td>
                    <button className="btn-sm" onClick={() => handleView(s)}>View</button>
                    <button className="btn-sm" onClick={() => handleEdit(s)}>Edit</button>
                    <button className="btn-sm btn-danger" onClick={() => handleDelete(s.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingShare && (
        <div className="modal-overlay" onClick={() => setViewingShare(null)}>
          <div className="modal-content view-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Share Details</h2>
              <button className="btn-close" onClick={() => setViewingShare(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="detail-section">
                <h3>Share Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Share Number:</strong> {viewingShare.share_number}</div>
                  <div className="detail-item"><strong>Member:</strong> {getMemberName(viewingShare.member_id)}</div>
                  <div className="detail-item"><strong>Number of Shares:</strong> {viewingShare.number_of_shares}</div>
                  <div className="detail-item"><strong>Share Price:</strong> Rs. {parseFloat(viewingShare.share_price || 0).toLocaleString()}</div>
                  <div className="detail-item"><strong>Total Amount:</strong> Rs. {parseFloat(viewingShare.total_amount || 0).toLocaleString()}</div>
                  <div className="detail-item"><strong>Purchase Date:</strong> {viewingShare.purchase_date_bs}</div>
                  <div className="detail-item"><strong>Status:</strong> <span className={`status-badge ${viewingShare.status}`}>{viewingShare.status}</span></div>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setViewingShare(null)}>Close</button>
              <button className="btn-primary" onClick={() => { handleEdit(viewingShare); setViewingShare(null); }}>Edit Share</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

