              <input type="text" value={form.saving_start_date_bs} onChange={e => setForm({...form, saving_start_date_bs: e.target.value})} placeholder="2080/01/01" />
            </div>
            <div className="form-group">
              <label>Interest Rate (%)</label>
              <input type="number" step="0.01" value={form.interest_rate} onChange={e => setForm({...form, interest_rate: e.target.value})} placeholder="6" />
            </div>
            <div className="form-group">
              <label>Status</label>
              <select value={form.status} onChange={e => setForm({...form, status: e.target.value})}>
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
              </select>
            </div>
          </div>
          <div className="form-actions">
            <button type="submit" className="btn-primary">{editingId ? 'Update Account' : 'Create Account'}</button>
            {editingId && <button type="button" className="btn-secondary" onClick={() => { setEditingId(null); setForm({ account_number: '', member_id: '', account_type: 'regular', current_balance: '0', deposit_amount: '', saving_start_date_bs: '', interest_rate: '6', status: 'active' }); }}>Cancel</button>}
          </div>
        </form>
      </div>

      <div className="table-section">
        <h3>Savings Accounts ({savings.length})</h3>
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Account No.</th>
                <th>Member</th>
                <th>Type</th>
                <th>Balance</th>
                <th>Rate</th>
                <th>Date</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {savings.map(s => (
                <tr key={s.id}>
                  <td>{s.account_number}</td>
                  <td>{getMemberName(s.member_id)}</td>
                  <td>{s.account_type}</td>
                  <td>Rs. {parseFloat(s.current_balance || 0).toLocaleString()}</td>
                  <td>{s.interest_rate}%</td>
                  <td>{s.saving_start_date_bs}</td>
                  <td><span className={`status-badge ${s.status}`}>{s.status}</span></td>
                  <td>
                    <button className="btn-sm" onClick={() => handleView(s)}>View</button>
                    <button className="btn-sm" onClick={() => handleEdit(s)}>Edit</button>
                    <button className="btn-sm btn-danger" onClick={() => handleDelete(s.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingSaving && (
        <div className="modal-overlay" onClick={() => setViewingSaving(null)}>
          <div className="modal-content view-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Savings Account Details</h2>
              <button className="btn-close" onClick={() => setViewingSaving(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="detail-section">
                <h3>Account Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Account Number:</strong> {viewingSaving.account_number}</div>
                  <div className="detail-item"><strong>Member:</strong> {getMemberName(viewingSaving.member_id)}</div>
                  <div className="detail-item"><strong>Type:</strong> {viewingSaving.account_type}</div>
                  <div className="detail-item"><strong>Current Balance:</strong> Rs. {parseFloat(viewingSaving.current_balance || 0).toLocaleString()}</div>
                  <div className="detail-item"><strong>Interest Rate:</strong> {viewingSaving.interest_rate}%</div>
                  <div className="detail-item"><strong>Start Date:</strong> {viewingSaving.saving_start_date_bs}</div>
                  <div className="detail-item"><strong>Status:</strong> <span className={`status-badge ${viewingSaving.status}`}>{viewingSaving.status}</span></div>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setViewingSaving(null)}>Close</button>
              <button className="btn-primary" onClick={() => { handleEdit(viewingSaving); setViewingSaving(null); }}>Edit Savings</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Monthly Savings Page
function MonthlySavingsPage() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [selectedYear, setSelectedYear] = useState(2081);
  const [savings, setSavings] = useState({});
  const [monthlyData, setMonthlyData] = useState([]);

  const months = [
    { name: 'Baisakh', bs: 1 }, { name: 'Jestha', bs: 2 }, { name: 'Ashadh', bs: 3 },
    { name: 'Shrawan', bs: 4 }, { name: 'Bhadra', bs: 5 }, { name: 'Ashoj', bs: 6 },
    { name: 'Kartik', bs: 7 }, { name: 'Mangsir', bs: 8 }, { name: 'Poush', bs: 9 },
    { name: 'Magh', bs: 10 }, { name: 'Falgun', bs: 11 }, { name: 'Chaitra', bs: 12 }
  ];

  useEffect(() => { fetchMembers(); }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const fetchMonthlySavings = async () => {
    if (selectedMember && selectedYear) {
      try {
        console.log('Fetching monthly savings for member:', selectedMember, 'year:', selectedYear);
        const response = await api.get(`/monthly-savings?member_id=${selectedMember}&year=${selectedYear}`);
        console.log('API response:', response);
        const data = response.data?.data || response.data || response || [];
        console.log('Monthly data:', data);
        console.log('Monthly data length:', data.length);
        setMonthlyData(Array.isArray(data) ? data : []);
        console.log('After setMonthlyData, current monthlyData length:', data.length);
      } catch (error) {
        console.error('Error fetching monthly savings:', error);
        setMonthlyData([]);
      }
    }
  };

  useEffect(() => {
    if (selectedMember && selectedYear) {
      fetchMonthlySavings();
    }
  }, [selectedMember, selectedYear]);

  console.log('Rendering - monthlyData length:', monthlyData.length);

  const getAmount = (month) => {
    const entry = monthlyData.find(m => m.month === month);
    return entry ? entry.amount : savings[month] || '';
  };

  const totalSaved = monthlyData.reduce((sum, m) => sum + parseFloat(m.amount || 0), 0);

  const handleSave = async (month) => {
    const amount = savings[month];
    const existingEntry = monthlyData.find(m => m.month === month);
    
    console.log('Saving monthly savings:', { month, amount, selectedMember, selectedYear, existingEntry });
    
    if (amount && selectedMember) {
      try {
        if (existingEntry) {
          // Update existing entry
          console.log('Updating existing entry:', existingEntry.id);
          await api.put(`/monthly-savings/${existingEntry.id}`, {
            member_id: selectedMember,
            year: selectedYear,
            month: month,
            amount: parseFloat(amount)
          });
          console.log('API result: Updated successfully');
          alert('Monthly savings updated!');
        } else {
          // Create new entry
          console.log('Creating new entry...');
          const result = await api.post('/monthly-savings', {
            member_id: selectedMember,
            year: selectedYear,
            month: month,
            amount: parseFloat(amount)
          });
          console.log('API result:', result);
          alert('Monthly savings saved!');
        }
        // Always refresh data after save/update
        fetchMonthlySavings();
        setSavings(prev => ({ ...prev, [month]: undefined }));
      } catch (error) {
        console.error('Error saving:', error);
        alert('Error saving: ' + error.message);
      }
    } else {
      console.log('Missing amount or selectedMember');
    }
  };

  const handleEdit = (month) => {
    const entry = monthlyData.find(m => m.month === month);
    if (entry) {
      setSavings(prev => ({ ...prev, [month]: entry.amount }));
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this entry?')) {
      try {
        await api.delete(`/monthly-savings/${id}`);
        fetchMonthlySavings();
      } catch (error) {
        console.error('Error deleting:', error);
      }
    }
  };

  return (
    <div className="monthly-savings-page">
      <div className="page-header">
        <h1>Monthly Savings</h1>
        <p>Track monthly savings contributions per member (Bikram Sambat calendar)</p>
      </div>
      <div className="form-section">
        <div className="form-row">
          <select value={selectedMember} onChange={e => { setSelectedMember(e.target.value); setMonthlyData([]); }}>
            <option value="">Select Member</option>
            {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
          </select>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)}>
            {[...Array(10)].map((_, i) => {
              const year = 2075 + i;
              return <option key={year} value={year}>{year} BS</option>;
            })}
          </select>
        </div>
      </div>
      {selectedMember && (
        <div className="monthly-content">
          <div className="summary-cards">
            <div className="summary-card">
              <h3>Member</h3>
              <div className="summary-value" style={{ fontSize: '1.2rem' }}>
                {members.find(m => m.id == selectedMember)?.member_name || 'Unknown'}
              </div>
            </div>
            <div className="summary-card">
              <h3>Year</h3>
              <div className="summary-value">{selectedYear} BS</div>
            </div>
            <div className="summary-card">
              <h3>Total Saved</h3>
              <div className="summary-value">Rs. {totalSaved.toLocaleString()}</div>
            </div>
            <div className="summary-card">
              <h3>Months Saved</h3>
              <div className="summary-value">{monthlyData.length}/12</div>
            </div>
            <div className="summary-card">
              <h3>Expected Annual</h3>
              <div className="summary-value">Rs. {(monthlyData.length * 1000).toLocaleString()}</div>
            </div>
          </div>
          <div className="monthly-grid">
            <h3>Monthly Contributions</h3>
            <p className="helper-text">Select a month, enter amount, and click Save. Edit or Delete existing entries.</p>
            <div className="months-container">
              {months.map(month => (
                <div key={month.bs} className="month-card">
                  <div className="month-header">
                    <span className="month-name">{month.name}</span>
                    <span className="month-number">{month.bs}</span>
                  </div>
                  <div className="month-input">
                    <label>Amount (Rs.)</label>
                    <input
                      type="number"
                      value={getAmount(month.bs)}
                      onChange={e => setSavings(prev => ({ ...prev, [month.bs]: e.target.value }))}
                      placeholder="0.00"
                    />
                  </div>
                  <div className="month-actions">
                    {monthlyData.find(m => m.month === month.bs) ? (
                      <>
                        <button className="btn-secondary" onClick={() => handleEdit(month.bs)}>Edit</button>
                        <button className="btn-danger" onClick={() => handleDelete(monthlyData.find(m => m.month === month.bs).id)}>Delete</button>
                      </>
                    ) : (
                      <button className="btn-primary" onClick={() => handleSave(month.bs)}>Save</button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="yearly-overview">
            <h3>Yearly Overview - {selectedYear} BS</h3>
            <p className="helper-text">Visual representation of all monthly contributions for the selected year</p>
            <div className="yearly-chart">
              {months.map(month => {
                const entry = monthlyData.find(m => m.month === month.bs);
                const amount = entry ? parseFloat(entry.amount) : 0;
                const maxAmount = Math.max(...monthlyData.map(m => parseFloat(m.amount || 0)), 1000);
                const height = Math.max((amount / maxAmount) * 150, 4);
                const hasEntry = monthlyData.some(m => m.month === month.bs);
                return (
                  <div key={month.bs} className={`chart-bar-container ${hasEntry ? 'has-data' : ''}`}>
                    <div className="chart-value">{amount > 0 ? `Rs. ${amount.toLocaleString()}` : '-'}</div>
                    <div className="chart-bar" style={{ height: `${height}px`, backgroundColor: amount > 0 ? '#10b981' : '#e5e7eb' }}></div>
                    <div className="chart-label">{month.name}</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Citizenship Page with Table View
function CitizenshipPage() {
  const [selectedMember, setSelectedMember] = useState('');
  const [members, setMembers] = useState([]);
  const [allCitizenships, setAllCitizenships] = useState([]);
  const [citizenshipData, setCitizenshipData] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [selectedDocument, setSelectedDocument] = useState(null);
  const [viewMode, setViewMode] = useState('table'); // 'table' or 'form'
  const [filter, setFilter] = useState('');
  const [photos, setPhotos] = useState({ photo: null, citizenship_front: null, citizenship_back: null });
  const [existingPhotos, setExistingPhotos] = useState({ photo: '', citizenship_front: '', citizenship_back: '' });
  
  const [formData, setFormData] = useState({
    full_name: '',
    citizenship_number: '',
    birth_date: '',
    birth_date_bs: '',
    nationality: '',
    marital_status: '',
    spouse_name: '',
    issued_date: '',
    issued_district: '',
    province: '',
    district: '',
    municipality: '',
    ward_number: '',
    tole: '',
    phone: '',
    email: ''
  });

  useEffect(() => { 
    fetchMembers(); 
    fetchAllCitizenships();
  }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const fetchAllCitizenships = async () => {
    try {
      const response = await api.get('/citizenship');
      const data = response.data || response || [];
      setAllCitizenships(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error('Error fetching citizenships:', error);
      setAllCitizenships([]);
    }
  };

  const handlePhotoChange = (e, field) => {
    const file = e.target.files[0];
    if (file) {
      setPhotos(prev => ({ ...prev, [field]: file }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      const form = new FormData();
      Object.keys(formData).forEach(key => form.append(key, formData[key]));
      form.append('member_id', selectedMember);
      
      if (photos.photo) form.append('photo', photos.photo);
      if (photos.citizenship_front) form.append('citizenship_front', photos.citizenship_front);
      if (photos.citizenship_back) form.append('citizenship_back', photos.citizenship_back);

      if (editingId) {
        await api.putForm(`/citizenship/${editingId}`, form);
        alert('Citizenship details updated successfully!');
      } else {
        await api.postForm('/citizenship', form);
        alert('Citizenship details saved successfully!');
      }
      
      resetForm();
      fetchAllCitizenships();
      fetchCitizenship();
    } catch (error) {
      console.error('Error saving citizenship:', error);
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchCitizenship = async () => {
    if (!selectedMember) {
      setCitizenshipData(null);
      return;
    }
    try {
      const response = await api.get(`/citizenship/member/${selectedMember}`);
      const data = response.data || response || null;
      setCitizenshipData(data);
      if (data) {
        setFormData({
          full_name: data.full_name || '',
          citizenship_number: data.citizenship_number || '',
          birth_date: data.birth_date || '',
          birth_date_bs: data.birth_date_bs || '',
          nationality: data.nationality || '',
          marital_status: data.marital_status || '',
          spouse_name: data.spouse_name || '',
          issued_date: data.issued_date || '',
          issued_district: data.issued_district || '',
          province: data.province || '',
          district: data.district || '',
          municipality: data.municipality || '',
          ward_number: data.ward_number || '',
          tole: data.tole || '',
          phone: data.phone || '',
          email: data.email || ''
        });
        setExistingPhotos({
          photo: data.photo || '',
          citizenship_front: data.citizenship_front || '',
          citizenship_back: data.citizenship_back || ''
        });
      }
    } catch (error) {
      console.error('Error fetching citizenship:', error);
      setCitizenshipData(null);
    }
  };

  useEffect(() => {
    fetchCitizenship();
  }, [selectedMember]);

  const handleDeletePhoto = async (field, id) => {
    if (window.confirm(`Delete this ${field} photo?`)) {
      try {
        await api.delete(`/citizenship/${id}/photo/${field}`);
        fetchCitizenship();
      } catch (error) {
        console.error('Error deleting photo:', error);
      }
    }
  };

  const resetForm = () => {
    setFormData({
      full_name: '',
      citizenship_number: '',
      birth_date: '',
      birth_date_bs: '',
      nationality: '',
      marital_status: '',
      spouse_name: '',
      issued_date: '',
      issued_district: '',
      province: '',
      district: '',
      municipality: '',
      ward_number: '',
      tole: '',
      phone: '',
      email: ''
    });
    setPhotos({ photo: null, citizenship_front: null, citizenship_back: null });
    setEditingId(null);
    setShowModal(false);
  };

  const handleEditFromTable = (doc) => {
    setSelectedMember(doc.member_id);
    setViewMode('form');
  };

  const handleViewFromTable = (doc) => {
    setSelectedDocument(doc);
    setShowDetailsModal(true);
  };

  const handleDeleteFromTable = async (id) => {
    if (window.confirm('Are you sure you want to delete this citizenship record?')) {
      try {
        await api.delete(`/citizenship/${id}`);
        fetchAllCitizenships();
      } catch (error) {
        console.error('Error deleting citizenship:', error);
      }
    }
  };

  const filteredCitizenships = allCitizenships.filter(c => 
    c.full_name?.toLowerCase().includes(filter.toLowerCase()) ||
    c.citizenship_number?.toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <div className="citizenship-page">
      <div className="page-header">
        <h1>Citizenship Details</h1>
        <p>Manage citizenship documents and personal information</p>
      </div>

      <div className="form-section">
        <h3>Select Member</h3>
        <div className="form-row">
          <select value={selectedMember} onChange={e => { setSelectedMember(e.target.value); setViewMode('table'); }}>
            <option value="">Select Member</option>
            {members.map(m => <option key={m.id} value={m.id}>{m.member_number} - {m.member_name}</option>)}
          </select>
          <button className="btn-primary" onClick={() => { setSelectedMember(''); setViewMode('table'); resetForm(); }}>Clear Selection</button>
        </div>
      </div>

      {selectedMember && (
        <div className="form-section">
          <div className="section-header">
            <h3>{editingId ? 'Edit Citizenship Details' : 'Add Citizenship Details'}</h3>
