                    <div className="photo-preview">
                      <img src={getImageUrl(existingPhotos.photo)} alt="Profile" />
                      <button type="button" className="btn-danger btn-sm" onClick={() => handleDeletePhoto('photo', citizenshipData?.id)}>Delete</button>
                    </div>
                  )}
                  <input type="file" accept="image/*" onChange={e => handlePhotoChange(e, 'photo')} />
                </div>

                <div className="photo-upload-group">
                  <label>Citizenship Front</label>
                  {existingPhotos.citizenship_front && (
                    <div className="photo-preview">
                      <img src={getImageUrl(existingPhotos.citizenship_front)} alt="Citizenship Front" />
                      <button type="button" className="btn-danger btn-sm" onClick={() => handleDeletePhoto('citizenship_front', citizenshipData?.id)}>Delete</button>
                    </div>
                  )}
                  <input type="file" accept="image/*" onChange={e => handlePhotoChange(e, 'citizenship_front')} />
                </div>

                <div className="photo-upload-group">
                  <label>Citizenship Back</label>
                  {existingPhotos.citizenship_back && (
                    <div className="photo-preview">
                      <img src={getImageUrl(existingPhotos.citizenship_back)} alt="Citizenship Back" />
                      <button type="button" className="btn-danger btn-sm" onClick={() => handleDeletePhoto('citizenship_back', citizenshipData?.id)}>Delete</button>
                    </div>
                  )}
                  <input type="file" accept="image/*" onChange={e => handlePhotoChange(e, 'citizenship_back')} />
                </div>
              </div>

              <div className="form-actions">
                <button type="submit" className="btn-primary" disabled={loading}>{loading ? 'Saving...' : (editingId ? 'Update' : 'Save')}</button>
                <button type="button" className="btn-secondary" onClick={resetForm}>Cancel</button>
              </div>
            </form>
          )}

          {viewMode === 'table' && citizenshipData && (
            <div className="citizenship-details">
              <div className="details-grid">
                <div className="detail-item"><strong>Name:</strong> {citizenshipData.full_name}</div>
                <div className="detail-item"><strong>Citizenship No:</strong> {citizenshipData.citizenship_number}</div>
                <div className="detail-item"><strong>Birth Date:</strong> {citizenshipData.birth_date_bs} (BS) / {citizenshipData.birth_date} (AD)</div>
                <div className="detail-item"><strong>Gender:</strong> {citizenshipData.gender}</div>
                <div className="detail-item"><strong>Nationality:</strong> {citizenshipData.nationality}</div>
                <div className="detail-item"><strong>Marital Status:</strong> {citizenshipData.marital_status}</div>
                <div className="detail-item"><strong>Spouse:</strong> {citizenshipData.spouse_name}</div>
                <div className="detail-item"><strong>Address:</strong> {citizenshipData.tole}, Ward {citizenshipData.ward_number}, {citizenshipData.municipality}, {citizenshipData.district}, {citizenshipData.province}</div>
                <div className="detail-item"><strong>Phone:</strong> {citizenshipData.phone}</div>
                <div className="detail-item"><strong>Email:</strong> {citizenshipData.email}</div>
              </div>
            </div>
          )}
        </div>
      )}

      <div className="table-section">
        <div className="section-header">
          <h3>All Citizenship Records ({filteredCitizenships.length})</h3>
          <input type="text" placeholder="Search by name or citizenship number..." value={filter} onChange={e => setFilter(e.target.value)} className="search-input" />
        </div>
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Citizenship No.</th>
                <th>Address</th>
                <th>Phone</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredCitizenships.map(doc => (
                <tr key={doc.id}>
                  <td>{doc.full_name}</td>
                  <td>{doc.citizenship_number}</td>
                  <td>{doc.tole}, {doc.municipality}, {doc.district}</td>
                  <td>{doc.phone}</td>
                  <td>
                    <button className="btn-sm" onClick={() => handleViewFromTable(doc)}>View</button>
                    <button className="btn-sm" onClick={() => handleEditFromTable(doc)}>Edit</button>
                    <button className="btn-sm btn-danger" onClick={() => handleDeleteFromTable(doc.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showDetailsModal && selectedDocument && (
        <div className="modal-overlay" onClick={() => setShowDetailsModal(false)}>
          <div className="modal-content view-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Citizenship Details</h2>
              <button className="btn-close" onClick={() => setShowDetailsModal(false)}>×</button>
            </div>
            <div className="modal-body">
              <div className="photo-gallery">
                {selectedDocument.photo && (
                  <div className="photo-item">
                    <img src={getImageUrl(selectedDocument.photo)} alt="Profile" />
                    <span>Profile Photo</span>
                  </div>
                )}
                {selectedDocument.citizenship_front && (
                  <div className="photo-item">
                    <img src={getImageUrl(selectedDocument.citizenship_front)} alt="Citizenship Front" />
                    <span>Citizenship Front</span>
                  </div>
                )}
                {selectedDocument.citizenship_back && (
                  <div className="photo-item">
                    <img src={getImageUrl(selectedDocument.citizenship_back)} alt="Citizenship Back" />
                    <span>Citizenship Back</span>
                  </div>
                )}
              </div>
              <div className="detail-section">
                <h3>Personal Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Full Name:</strong> {selectedDocument.full_name}</div>
                  <div className="detail-item"><strong>Citizenship Number:</strong> {selectedDocument.citizenship_number}</div>
                  <div className="detail-item"><strong>Gender:</strong> {selectedDocument.gender}</div>
                  <div className="detail-item"><strong>Birth Date:</strong> {selectedDocument.birth_date_bs} (BS) / {selectedDocument.birth_date} (AD)</div>
                  <div className="detail-item"><strong>Birth Place:</strong> {selectedDocument.birth_place}</div>
                  <div className="detail-item"><strong>Nationality:</strong> {selectedDocument.nationality}</div>
                  <div className="detail-item"><strong>Religion:</strong> {selectedDocument.religion}</div>
                  <div className="detail-item"><strong>Marital Status:</strong> {selectedDocument.marital_status}</div>
                  <div className="detail-item"><strong>Spouse Name:</strong> {selectedDocument.spouse_name}</div>
                </div>
              </div>
              <div className="detail-section">
                <h3>Address</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Province:</strong> {selectedDocument.province}</div>
                  <div className="detail-item"><strong>District:</strong> {selectedDocument.district}</div>
                  <div className="detail-item"><strong>Municipality:</strong> {selectedDocument.municipality}</div>
                  <div className="detail-item"><strong>Ward:</strong> {selectedDocument.ward_number}</div>
                  <div className="detail-item"><strong>Tole:</strong> {selectedDocument.tole}</div>
                </div>
              </div>
              <div className="detail-section">
                <h3>Contact</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Phone:</strong> {selectedDocument.phone}</div>
                  <div className="detail-item"><strong>Email:</strong> {selectedDocument.email}</div>
                </div>
              </div>
              <div className="detail-section">
                <h3>Issued Information</h3>
                <div className="detail-grid">
                  <div className="detail-item"><strong>Issued District:</strong> {selectedDocument.issued_district}</div>
                  <div className="detail-item"><strong>Issued Date:</strong> {selectedDocument.issued_date}</div>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-secondary" onClick={() => setShowDetailsModal(false)}>Close</button>
              <button className="btn-primary" onClick={() => { setShowDetailsModal(false); setSelectedMember(selectedDocument.member_id); setViewMode('form'); handleEditFromTable(selectedDocument); }}>
                Edit Details
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Profile Page
function ProfilePage() {
  const [user, setUser] = useState(null);
  const [form, setForm] = useState({
    full_name: '',
    email: '',
    username: '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });
  const [photo, setPhoto] = useState(null);
  const [existingPhoto, setExistingPhoto] = useState('');
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    if (storedUser) {
      const userData = JSON.parse(storedUser);
      setUser(userData);
      setForm({
        full_name: userData.full_name || '',
        email: userData.email || '',
        username: userData.username || '',
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
      });
      setExistingPhoto(userData.profile_photo || '');
    }
  }, []);

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setPhoto(file);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      const formData = new FormData();
      formData.append('full_name', form.full_name);
      formData.append('email', form.email);
      
      if (photo) {
        formData.append('photo', photo);
      }

      if (form.newPassword) {
        if (form.newPassword !== form.confirmPassword) {
          setMessage('New passwords do not match!');
          setLoading(false);
          return;
        }
        formData.append('newPassword', form.newPassword);
      }

      const token = localStorage.getItem('token');
      const res = await fetch(`${API_BASE}/profile`, {
        method: 'PUT',
        headers: { 'Authorization': `Bearer ${token}` },
        body: formData
      });

      const data = await res.json();
      
      if (data.success) {
        const updatedUser = { ...user, ...data.user };
        localStorage.setItem('user', JSON.stringify(updatedUser));
        setUser(updatedUser);
        setExistingPhoto(data.user.profile_photo || '');
        setPhoto(null);
        setForm(prev => ({ ...prev, currentPassword: '', newPassword: '', confirmPassword: '' }));
        setMessage('Profile updated successfully!');
      } else {
        setMessage(data.error || 'Failed to update profile');
      }
    } catch (error) {
      setMessage('Error updating profile: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    window.location.href = '/';
  };

  if (!user) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="profile-page">
      <div className="page-header">
        <h1>Profile Settings</h1>
        <p>Manage your account settings and profile</p>
      </div>

      <div className="profile-container">
        <div className="profile-sidebar">
          <div className="profile-photo-section">
            {existingPhoto ? (
              <img src={getImageUrl(existingPhoto)} alt="Profile" className="profile-photo" />
            ) : (
              <div className="profile-photo-placeholder">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
                  <circle cx="12" cy="7" r="4"/>
                </svg>
              </div>
            )}
            <label htmlFor="photo-upload" className="photo-upload-label">
              Change Photo
            </label>
            <input type="file" id="photo-upload" accept="image/*" onChange={handlePhotoChange} />
          </div>
          <h3>{user.full_name || user.username}</h3>
          <p className="role-badge">{user.role}</p>
          <button className="btn-logout-sidebar" onClick={handleLogout}>Logout</button>
        </div>

        <div className="profile-content">
          <form onSubmit={handleSubmit}>
            <div className="form-section-title">Personal Information</div>
            <div className="form-row">
              <div className="form-group">
                <label>Full Name</label>
                <input type="text" value={form.full_name} onChange={e => setForm({...form, full_name: e.target.value})} />
              </div>
              <div className="form-group">
                <label>Email</label>
                <input type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
              </div>
            </div>
            <div className="form-group">
              <label>Username</label>
              <input type="text" value={form.username} disabled className="disabled-input" />
            </div>

            <div className="form-section-title">Change Password</div>
            <div className="form-row">
              <div className="form-group">
                <label>Current Password</label>
                <input type="password" value={form.currentPassword} onChange={e => setForm({...form, currentPassword: e.target.value})} />
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>New Password</label>
                <input type="password" value={form.newPassword} onChange={e => setForm({...form, newPassword: e.target.value})} />
              </div>
              <div className="form-group">
                <label>Confirm New Password</label>
                <input type="password" value={form.confirmPassword} onChange={e => setForm({...form, confirmPassword: e.target.value})} />
              </div>
            </div>

            {message && <div className={`message ${message.includes('success') ? 'success' : 'error'}`}>{message}</div>}

            <div className="form-actions">
              <button type="submit" className="btn-primary" disabled={loading}>{loading ? 'Saving...' : 'Save Changes'}</button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

// Main App
function App() {
  const isAuthenticated = () => {
    const token = localStorage.getItem('token');
    return !!token;
  };

  return (
    <Router>
      <Routes>
        <Route path="/" element={<LoginPage />} />
        <Route path="/dashboard" element={isAuthenticated() ? <Dashboard /> : <Navigate to="/" />} />
        <Route path="/members" element={isAuthenticated() ? <MembersPage /> : <Navigate to="/" />} />
        <Route path="/loans" element={isAuthenticated() ? <LoansPage /> : <Navigate to="/" />} />
        <Route path="/shares" element={isAuthenticated() ? <SharesPage /> : <Navigate to="/" />} />
        <Route path="/savings" element={isAuthenticated() ? <SavingsPage /> : <Navigate to="/" />} />
        <Route path="/monthly-savings" element={isAuthenticated() ? <MonthlySavingsPage /> : <Navigate to="/" />} />
        <Route path="/citizenship" element={isAuthenticated() ? <CitizenshipPage /> : <Navigate to="/" />} />
        <Route path="/profile" element={isAuthenticated() ? <ProfilePage /> : <Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default App;
